    }

    // 设置线程上下文
    let mut new_tcb = new_task.tcb.write();
    new_tcb.cx = self.task.tcb.read().cx.clone();
    new_tcb.cx[TrapFrameArgs::RET] = 0; // 子进程返回 0
    if newsp != 0 {
        new_tcb.cx[TrapFrameArgs::SP] = newsp;
    }

    // 注册到执行器
    thread::spawn(new_task.clone(), user_entry());
    Ok(new_task.task_id)
}
```

**完整度评估**：80%
- ✓ 支持进程和线程概念分离
- ✓ 实现 fork/clone 系统调用
- ✓ 支持 COW 的内存复制
- ✓ 文件描述符表继承
- ✓ 父子进程关系维护
- ✗ 缺少进程组完整支持
- ✗ 缺少会话（session）管理
- ✗ 缺少完整的进程优先级调度

---

